  "inlineSchema": "datasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\nmodel Part {\n  id          String       @id @default(cuid())\n  partNumber  String       @unique\n  partDesc    String?\n  createdAt   DateTime     @default(now())\n  updatedAt   DateTime     @updatedAt\n  vendorParts VendorPart[]\n  ncrs        Ncr[]\n  qprParts    QprPart[]\n}\n\nmodel Vendor {\n  id                  String               @id @default(cuid())\n  vendorCode          String               @unique\n  vendorName          String?              @unique\n  createdAt           DateTime?            @default(now())\n  updatedAt           DateTime?            @updatedAt\n  vendorParts         VendorPart[]\n  ncrs                Ncr[]\n  qprs                Qpr[]\n  confirmationLetters ConfirmationLetter[]\n}\n\nmodel VendorPart {\n  id        String   @id @default(cuid())\n  vendorId  String\n  vendor    Vendor   @relation(fields: [vendorId], references: [id])\n  partId    String\n  part      Part     @relation(fields: [partId], references: [id])\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([vendorId, partId]) // Memastikan kombinasi part-vendor unik\n}\n\nmodel Ncr {\n  id                         String       @id @default(cuid())\n  code                       String       @unique\n  date                       DateTime     @default(now())\n  partId                     String\n  part                       Part         @relation(fields: [partId], references: [id])\n  vendorId                   String\n  vendor                     Vendor       @relation(fields: [vendorId], references: [id])\n  location                   Location?\n  problemType                ProblemType?\n  description                String?\n  disposition                Disposition?\n  isRequiredCustomerApproval Boolean?\n  details                    Json?\n\n  // Relasi 1-to-1 ke Progres Approval (Checksum tanda tangan digital)\n  ncrApprovalProgress NcrApprovalProgress?\n\n  // Relasi Many-to-Many ke User (Inspektur bisa lebih dari satu)\n  inspectors User[] @relation(\"NcrInspectors\")\n}\n\nmodel NcrApprovalProgress {\n  id                          String    @id @default(cuid())\n  ncrId                       String    @unique // Diperlukan unik untuk relasi 1-to-1\n  ncr                         Ncr       @relation(fields: [ncrId], references: [id])\n  checksumApprovalSectionHead Bytes?\n  checksumApprovalDeptHead    Bytes?\n  createdAt                   DateTime? @default(now())\n  updatedAt                   DateTime? @default(now())\n}\n\nmodel User {\n  id   String @id @default(cuid())\n  name String\n  npk  Int    @unique\n\n  // Relasi Terbalik Many-to-Many ke Ncr\n  inspectedNcrs Ncr[] @relation(\"NcrInspectors\")\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nenum Location {\n  INCOMING\n  OUTGOING\n  IN_PROCESS\n  CUSTOMER\n}\n\nenum ProblemType {\n  QUALITY\n  QUANTITY\n}\n\nenum Disposition {\n  RETURN_TO_VENDOR\n  REWORK\n  SCRAP\n  ACCEPT_AS_IS\n  REPAIR\n  REGRADE\n}\n\nmodel Qpr {\n  id                 String               @id @default(cuid())\n  qprNumber          String               @unique\n  date               DateTime             @default(now())\n  vendorId           String\n  vendor             Vendor               @relation(fields: [vendorId], references: [id])\n  status             QprStatus            @default(WAITING_APPROVAL)\n  requiredRole       String\n  refNcrNumber       String?\n  problem            String?\n  claimType          String?\n  totalQty           Int\n  totalQtyNg         Int\n  totalStdAllowance  Int\n  billableQty        Int\n  claimAmount        Float?\n  qprParts           QprPart[]\n  approvalProgress   QprApprovalProgress?\n  confirmationLetter ConfirmationLetter?\n  createdAt          DateTime             @default(now())\n  updatedAt          DateTime             @updatedAt\n}\n\nmodel QprPart {\n  id           String   @id @default(cuid())\n  qprId        String\n  qpr          Qpr      @relation(fields: [qprId], references: [id])\n  partId       String\n  part         Part     @relation(fields: [partId], references: [id])\n  totalQty     Int\n  qtyNg        Int\n  stdAllowance Int\n  qtyClaim     Int\n  unitPrice    Float?\n  taxRate      Float?\n  createdAt    DateTime @default(now())\n  updatedAt    DateTime @updatedAt\n}\n\nmodel QprApprovalProgress {\n  id                  String   @id @default(cuid())\n  qprId               String   @unique\n  qpr                 Qpr      @relation(fields: [qprId], references: [id])\n  checksumSectionHead Bytes?\n  checksumDeptHead    Bytes?\n  checksumDivHead     Bytes?\n  checksumVendor      Bytes?\n  createdAt           DateTime @default(now())\n  updatedAt           DateTime @updatedAt\n}\n\nmodel ConfirmationLetter {\n  id         String      @id @default(cuid())\n  clNumber   String      @unique\n  dateSent   DateTime    @default(now())\n  qprId      String      @unique\n  qpr        Qpr         @relation(fields: [qprId], references: [id])\n  vendorId   String\n  vendor     Vendor      @relation(fields: [vendorId], references: [id])\n  amount     Float\n  status     ClStatus    @default(PENDING)\n  sscBilling SscBilling?\n  sscPayment SscPayment?\n  createdAt  DateTime    @default(now())\n  updatedAt  DateTime    @updatedAt\n}\n\nmodel SscBilling {\n  id          String             @id @default(cuid())\n  clId        String             @unique\n  cl          ConfirmationLetter @relation(fields: [clId], references: [id])\n  billingNo   String             @unique\n  billingDate DateTime           @default(now())\n  totalAmount Float\n  status      BillingStatus      @default(UNPAID)\n  createdAt   DateTime           @default(now())\n  updatedAt   DateTime           @updatedAt\n}\n\nmodel SscPayment {\n  id          String             @id @default(cuid())\n  clId        String             @unique\n  cl          ConfirmationLetter @relation(fields: [clId], references: [id])\n  paymentNo   String             @unique\n  paymentDate DateTime           @default(now())\n  amountPaid  Float\n  bankName    String?\n  accountNo   String?\n  status      PaymentStatus      @default(PENDING)\n  createdAt   DateTime           @default(now())\n  updatedAt   DateTime           @updatedAt\n}\n\nenum QprStatus {\n  WAITING_APPROVAL\n  WAITING_VENDOR\n  APPROVED_BY_VENDOR\n  APPROVED\n  CLOSED\n  CLOSED_PAID\n}\n\nenum ClStatus {\n  PENDING\n  APPROVED\n  REJECTED\n}\n\nenum BillingStatus {\n  UNPAID\n  PAID\n}\n\nenum PaymentStatus {\n  PENDING\n  SUCCESS\n  FAILED\n}\n",
